typedef float fp;

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

__global__ void extract_kernel(long d_Ne, fp *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__global__ void prepare_kernel(long d_Ne, fp *d_I, fp *d_sums, fp *d_sums2) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__global__ void reduce_kernel(long d_Ne, long d_no, int d_mul, fp *d_sums, fp *d_sums2, int blocks2_work_size) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;
    int gridDim_x = get_num_groups(0);
    int nf = NUMBER_THREADS - (gridDim_x * NUMBER_THREADS - d_no);
    int df = 0;

    fp d_psum[NUMBER_THREADS];
    fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            __syncthreads();
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (gridDim_x - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__global__ void srad_kernel(fp lambda, int Nr, int Nc, long Ne, 
                            const int *d_iN, const int *d_iS, const int *d_jE, const int *d_jW,
                            fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                            fp q0sqr, fp *d_c, fp *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int k = (bx * NUMBER_THREADS) + tx;

    if (k < Ne) {
        int i = k / Nc;
        int j = k % Nc;

        fp Jc = d_I[k];

        int iN_idx = d_iN[i];
        int iS_idx = d_iS[i];
        int jW_idx = d_jW[j];
        int jE_idx = d_jE[j];

        d_dN[k] = d_I[iN_idx * Nc + j] - Jc;
        d_dS[k] = d_I[iS_idx * Nc + j] - Jc;
        d_dW[k] = d_I[i * Nc + jW_idx] - Jc;
        d_dE[k] = d_I[i * Nc + jE_idx] - Jc;

        fp G2 = (d_dN[k] * d_dN[k] + d_dS[k] * d_dS[k] + d_dW[k] * d_dW[k] + d_dE[k] * d_dE[k]) / (Jc * Jc);
        fp L = (d_dN[k] + d_dS[k] + d_dW[k] + d_dE[k]) / Jc;

        fp num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        d_c[k] = c_val;
    }
}

__global__ void srad2_kernel(fp lambda, int Nr, int Nc, long Ne,
                             const int *d_iN, const int *d_iS, const int *d_jE, const int *d_jW,
                             fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                             fp *d_c, fp *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int k = (bx * NUMBER_THREADS) + tx;

    if (k < Ne) {
        int i = k / Nc;
        int j = k % Nc;

        int iS_idx = d_iS[i];
        int jE_idx = d_jE[j];

        fp cN = d_c[k];
        fp cS = d_c[iS_idx * Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[i * Nc + jE_idx];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__global__ void compress_kernel(long d_Ne, fp *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
